exercise.solution_code:
#include <iostream>
#include <string>

int countNegatives(const int* arr, int size, int* outMin) {
    int count { 0 };
    for (int i { 0 }; i < size; ++i) {
        if (arr[i] < 0) {
            if (count == 0 && outMin) {
                *outMin = arr[i];
            } else if (outMin && arr[i] < *outMin) {
                *outMin = arr[i];
            }
            ++count;
        }
    }
    return count;
}

int main() {
    int n{};
    std::cin >> n;

    int arr[20]{};
    for (int i { 0 }; i < n; ++i)
        std::cin >> arr[i];

    std::string wantMin{};
    std::cin >> wantMin;

    int minVal{};
    int count{};

    if (wantMin == "yes") {
        count = countNegatives(arr, n, &minVal);
        std::cout << "Count: " << count << '\n';
        if (count > 0)
            std::cout << "Min negative: " << minVal << '\n';
        else
            std::cout << "No negatives\n";
    } else {
        count = countNegatives(arr, n, nullptr);
        std::cout << "Count: " << count << '\n';
    }

    return 0;
}
